     9→} from './storefront-api-types.js';
    10→import type {PartialDeep, Simplify} from 'type-fest';
    11→import {flattenConnection} from './flatten-connection.js';
    12→import {RootASTNode as RichTextRootASTNode} from './RichText.types.js';
    13→
    14→/**
    15→ * A function that uses `metafield.type` to parse the Metafield's `value` or `reference` or `references` (depending on the `metafield.type`) and places the result in `metafield.parsedValue`
    16→ *
    17→ * TypeScript developers can use the type `ParsedMetafields` from this package to get the returned object's type correct. For example:
    18→ *
    19→ * ```
    20→ * parseMetafield<ParsedMetafields['boolean']>({type: 'boolean', value: 'false'}
    21→ * ```
    22→ */
    23→export function parseMetafield<ReturnGeneric>(
    24→  metafield: PartialDeep<MetafieldBaseType, {recurseIntoArrays: true}>,
    25→): ReturnGeneric {
    26→  if (!metafield.type) {
    27→    const noTypeError = `parseMetafield(): The 'type' field is required in order to parse the Metafield.`;
    28→    if (__HYDROGEN_DEV__) {
    29→      throw new Error(noTypeError);
    30→    } else {
    31→      console.error(`${noTypeError} Returning 'parsedValue' of 'null'`);
    32→      return {
    33→        ...metafield,
    34→        parsedValue: null,
    35→      } as ReturnGeneric;
    36→    }
    37→  }
    38→
    39→  switch (metafield.type) {
    40→    case 'boolean':
    41→      return {
    42→        ...metafield,
    43→        parsedValue: metafield.value === 'true',
    44→      } as ReturnGeneric;
    45→
    46→    case 'collection_reference':
    47→    case 'file_reference':
    48→    case 'page_reference':
    49→    case 'product_reference':
    50→    case 'variant_reference':
    51→      return {
    52→        ...metafield,
    53→        parsedValue: metafield.reference,
    54→      } as ReturnGeneric;
    55→
    56→    case 'color':
    57→    case 'multi_line_text_field':
    58→    case 'single_line_text_field':
    59→    case 'url':
    60→      return {
    61→        ...metafield,
    62→        parsedValue: metafield.value,
    63→      } as ReturnGeneric;
    64→
    65→    // TODO: 'money' should probably be parsed even further to like `useMoney()`, but that logic needs to be extracted first so it's not a hook
    66→    case 'dimension':
    67→    case 'money':
    68→    case 'json':
    69→    case 'rating':
    70→    case 'volume':
    71→    case 'weight':
    72→    case 'rich_text_field':
    73→    case 'list.color':
    74→    case 'list.dimension':
    75→    case 'list.number_integer':
    76→    case 'list.number_decimal':
    77→    case 'list.rating':
    78→    case 'list.single_line_text_field':
    79→    case 'list.url':
    80→    case 'list.volume':
    81→    case 'list.weight': {
    82→      let parsedValue = null;
    83→      try {
    84→        parsedValue = parseJSON(metafield.value ?? '');
    85→      } catch (err) {
    86→        const parseError = `parseMetafield(): attempted to JSON.parse the 'metafield.value' property, but failed.`;
    87→        if (__HYDROGEN_DEV__) {
    88→          throw new Error(parseError);
    89→        } else {
    90→          console.error(`${parseError} Returning 'null' for 'parsedValue'`);
    91→        }
    92→        parsedValue = null;
    93→      }
    94→      return {
    95→        ...metafield,
    96→        parsedValue,
    97→      } as ReturnGeneric;
    98→    }
    99→
   100→    case 'date':
   101→    case 'date_time':
   102→      return {
   103→        ...metafield,
   104→        parsedValue: new Date(metafield.value ?? ''),
