   109→      const jsonParseValue = parseJSON(metafield?.value ?? '') as string[];
   110→      return {
   111→        ...metafield,
   112→        parsedValue: jsonParseValue.map((dateString) => new Date(dateString)),
   113→      } as ReturnGeneric;
   114→    }
   115→
   116→    case 'number_decimal':
   117→    case 'number_integer':
   118→      return {
   119→        ...metafield,
