   139→          `${typeNotFoundError}  Returning 'parsedValue' of 'null'`,
   140→        );
   141→        return {
   142→          ...metafield,
   143→          parsedValue: null,
   144→        } as ReturnGeneric;
   145→      }
   146→    }
   147→  }
   148→}
