   150→/**
   151→ * Parses a JSON string while preventing prototype injection attacks.
   152→ */
   153→export function parseJSON(json: string): unknown {
   154→  if (String(json).includes('__proto__')) {
   155→    return JSON.parse(json, (k, v) => {
   156→      if (k !== '__proto__') return v as unknown;
   157→    }) as unknown;
   158→  }
   159→  return JSON.parse(json) as unknown;
   160→}
