import {describe, it, expect} from 'vitest';
import {parseMetafield, type ParsedMetafields, type MoneyV2} from './packages/hydrogen-react/src/parse-metafield.js';

describe('parseMetafield money type bug', () => {
  it('should correctly parse money metafield with currency_code', () => {
    // This reproduces the bug described in the issue
